long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    // Precompute teleport lists
    vector<vector<vector<pair<int, int>>>> teleport_list(m, vector<vector<pair<int, int>>>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleport_list[i][j].push_back({x, y});
                    }
                }
            }
        }
    }

    // Initialize distance array with INF
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k+1, LLONG_MAX)));
    dist[0][0][0] = 0;

    // Priority queue: (cost, i, j, t)
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<tuple<long long, int, int, int>>> pq;
    pq.push({0, 0, 0, 0});

    while (!pq.empty()) {
        auto [cost, i, j, t] = pq.top();
        pq.pop();

        // Check if destination is reached
        if (i == m-1 && j == n-1) {
            return cost;
        }

        // If current cost is higher than the recorded distance, skip
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Normal moves: right and down
        // Right move
        if (j + 1 < n) {
            long long new_cost = cost + grid[i][j+1];
            if (new_cost < dist[i][j+1][t]) {
                dist[i][j+1][t] = new_cost;
                pq.push({new_cost, i, j+1, t});
            }
        }
        // Down move
        if (i + 1 < m) {
            long long new_cost = cost + grid[i+1][j];
            if (new_cost < dist[i+1][j][t]) {
                dist[i+1][j][t] = new_cost;
                pq.push({new_cost, i+1, j, t});
            }
        }

        // Teleport moves
        for (auto [x, y] : teleport_list[i][j]) {
            if (t < k) {
                long long new_t = t + 1;
                long long new_cost = cost;
                if (new_cost < dist[x][y][new_t]) {
                    dist[x][y][new_t] = new_cost;
                    pq.push({new_cost, x, y, new_t});
                }
            }
        }
    }

    // If not found (should not happen as per problem constraints)
    return -1;
}

