    const n = grid[0].length;

    // Precompute teleport lists
    const teleportList: Array<Array<Array<[number, number]>>> = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => []));
    for (let i = 0; i < m; ++i) {
        for (let j = 0; j < n; ++j) {
            for (let x = 0; x < m; ++x) {
                for (let y = 0; y < n; ++y) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Initialize distance array
    const INF = Number.MAX_VALUE;
    const dist: number[][][] = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(INF)));
    dist[0][0][0] = 0;

    // Priority queue
    const pq: [number, number, number, number][] = [];
    pq.push([0, 0, 0, 0]);

    // Sift up and sift down functions
    function push(cost: number, i: number, j: number, t: number) {
        pq.push([cost, i, j, t]);
        let idx = pq.length - 1;
        while (idx > 0) {
            const parent = Math.floor((idx - 1) / 2);
            if (pq[idx][0] < pq[parent][0]) {
                [pq[idx], pq[parent]] = [pq[parent], pq[idx]];
                idx = parent;
            } else {
                break;
            }
        }
    }

    function pop(): [number, number, number, number] {
        if (pq.length === 0) return [INF, -1, -1, -1];
        const min = pq[0];
        pq[0] = pq[pq.length - 1];
        pq.pop();
        let idx = 0;
        while (true) {
            let left = 2 * idx + 1;
            let right = 2 * idx + 2;
            let smallest = idx;
            if (left < pq.length && pq[left][0] < pq[smallest][0]) {
                smallest = left;
            }
            if (right < pq.length && pq[right][0] < pq[smallest][0]) {
                smallest = right;
            }
            if (smallest === idx) break;
            [pq[idx], pq[smallest]] = [pq[smallest], pq[idx]];
            idx = smallest;
        }
        return min;
    }

    while (pq.length > 0) {
        const [cost, i, j, t] = pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
