    // Priority queue implementation
    class PriorityQueue {
        private heap: [number, number, number, number][] = [];
        push(cost: number, i: number, j: number, t: number) {
            this.heap.push([cost, i, j, t]);
            this.siftUp(this.heap.length - 1);
        }
        pop(): [number, number, number, number] {
            if (this.heap.length === 0) return [0, 0, 0, 0];
            const min = this.heap[0];
